import jibo = require('jibo');
import Be from './Be';

import {BeSkill, ExitOptions} from '@be/be-framework';

type Options = Partial<jibo.jetstream.types.ListenResult> & {lastSkill?: string, exitOptions?: ExitOptions};

class SkillSwitchData {

    private _skill: BeSkill;
    private _options: Options;

    constructor(skill: BeSkill, options: Options) {
        if(!options) {
            options = {};
        }
        //safety check due to ASR/NLU format change
        if (!options.asr) {
            options.asr = {text:'', confidence:1};
        }
        if (options.nlu && !options.nlu.entities) {
            options.nlu.entities = {};
        }

        this._skill = skill;
        this._options = options;
    }

    get skill(): BeSkill {
        return this._skill;
    }

    get name(): string {
        return this._skill.assetPack;
    }

    get options(): Options {
        return this._options;
    }

    get priority(): number {
        // restore is a higher priority than error skill because we wan't to be able to block error skill switching
        // while we're calling the jibo.systemManager.restore call to all our services
        if (this.name === "@be/restore") {
            return 7;
        }
        else if (this._options.nlu && this.name === "@be/settings") {
            if (this._options.nlu.intent === "wipe") {
                return 6;  // don't interrupt wipe please...
            }
            else if (this._options.nlu.entities.errorId) {
                return 5;
            }
        }
        else if (this.name === "@be/tutorial" || this.name === "@be/first-contact") {
           return 4;
        }
        else if (this._options.nlu && this.name === "@be/clock" && this._options.nlu.intent === "finished" &&
            ((this._options.nlu.entities.domain === "alarm" ) || (this._options.nlu.entities.domain === "timer"))) {
            return 3;
        }
        // skills that are proactively launched are a lower priority than any be skill except for idle 
        // the reasoning being that robot-initiated behaviors should not interrupt the original user-requested task
        else if (this._options.match && this._options.match.isProactive) {
            return 1;
        }
        else if (this.name === "@be/idle") {
            return 0;
        }

        // default
        return 2;
    }
}

export default SkillSwitchData;
export {Options};