// NOTE: these states are in order. in that, with the exception of lifecycle ended
// all states can only be transitioned to in a SkillLifecycle if the previous state has been reached
enum SkillLifecycleState {
    // default state
    NONE = 0,
    // request a skill for a pending skill redirect
    SKILL_SWITCH_REQUESTED = 1,
    // a skill is currently pending
    SKILL_SWITCH_PENDING = 2,
    // a skill's init / open sequence is about to start
    SKILL_START_OPEN = 4,
    // a skill's open method has been called and the skill should be running
    SKILL_OPENED = 5,
    // a skill's lifecycle has been ended
    // NOTE: this is NOT synonymous with a skill's close method being called
    // see SkillLifecycleEndState for a full list of reasons why the skill's lifecycle may be ended
    LIFECYCLE_ENDED = 6
};

export default SkillLifecycleState;
