/**
 * Static methods to manipulate the date on the robot or in sim in debug mode.
 */

class DateSetter {

    private static _origDate:DateConstructor;

    /**
     * Set the javascript date. The fake date will be updated every time a new date is created or Date.now() is called.
     * @param {Number} year of fake date
     * @param {Number} month of fake date, indexed by 1 for usability.
     * @param {Number} day of fake date
     * @param {Number} hours optional, defaults to 12 (noon)
     * @param {Number} minutes optional, defaults to 0
     * @param {Number} seconds optional, defaults to 0
     */
    static shiftDate(year: number, month: number, day: number, hours: number=12, minutes: number=0, seconds: number=0): void {
        // the only thing that's zero-indexed in the 'new Date' method is months, so for usability we're gonna index by 1.
        if (month <= 0) {
            console.warn(`${month} found for month, replacing with 1. Fake dates are indexed by 1 on input for usability.`);
            month = 1;
        }

        // Restore if we had already overwritten Date
        if (this._origDate) {
            global.Date = this._origDate;
        }

        const OrigDate = global.Date;
        this._origDate = OrigDate;

        // Create a fake date and record its real start time
        const fakeDateArgs = [year, month-1, day, hours, minutes, seconds]; // Offset month for ease of use.

        const fakeDate: Date = Reflect.construct(OrigDate, fakeDateArgs); // eslint-disable-line no-undef
        const fakeDateStartTime = OrigDate.now();

        // Override Date constructor
        (global as any).Date = function(): Date {
            if (arguments.length === 0) { // This is a call to new Date(), replace the arguments with the fake date information
                const updatedFakeDateMs = fakeDate.getTime() + (OrigDate.now() - fakeDateStartTime);
                // equivalent to `new Date(ms)
                return Reflect.construct(OrigDate, [updatedFakeDateMs]); // eslint-disable-line no-undef
            } else {
                return Reflect.construct(OrigDate, arguments); // eslint-disable-line no-undef
            }
        };
        // Give new Date all the original prototype methods
        (global.Date as any).prototype = OrigDate.prototype;

        // Do the actual time offset
        global.Date.now = function () {
            const timeSinceFakeDateStart = (OrigDate.now() - fakeDateStartTime); // offset from the start of the time.
            return fakeDate.getTime() + timeSinceFakeDateStart;
        };

        // Assign two remaining static functions
        global.Date.parse = OrigDate.parse;
        global.Date.UTC = OrigDate.UTC;

        console.log(`Setting up fake Date of: ${fakeDate.toString()}.`);
    }

    /**
     * Restore the fake date.
     */
    static restoreDate(): void {
        if (this._origDate) {
            global.Date = this._origDate;
            this._origDate = null;
            console.info(`Date Restored to: ${(new Date()).toString()}.`);
        } else {
            console.warn('No fake Date to restore.');
        }
    }
}

export default DateSetter;
