import {Log} from 'jibo-log';
import jibo = require('jibo');
import fs = require('fs');
import path = require('path');

Log.processName = "be";

const log: Log = new Log('Be');
export default log;

/**
 * Loads the log configuration if we're running on robot
 * If we are running locally then the log config comes from `[home dir]/.jibo/logging.json`
 * @param {Function} callback
 */
export function loadLogConfig(callback: (error?: string) => void): void {
    if (jibo.runMode === jibo.RunMode.ON_ROBOT) {
        // We check in the local config directory using the mode
        jibo.systemManager.getMode((err, mode) => {
            const configPath = path.join(jibo.utils.PathUtils.findRoot(), 'config', `be-${mode}.json`);
            if (fs.existsSync(configPath)) {
                let encounteredError = false;
                try {
                    Log.loadConfig(JSON.parse(fs.readFileSync(configPath, 'utf-8')));
                    log.info(`Loaded log configuration from '${configPath}'`);
                }
                catch (err) {
                    encounteredError = true;
                    callback(`Error parsing logging config file '${configPath}': ${err.message}`);
                }
                // Can't call the callback in the try block, or we risk calling
                // the callback twice, if the callback eventually throws an
                // error
                if (!encounteredError) {
                    callback();
                }
            } else {
                callback(`No logging configuration found at '${configPath}'`);
            }
        });
    } else {
        // Load up an empty config, so that the home-dir config will be loaded
        Log.loadConfig({});
        callback();
    }
}
