// at the end of a skill's lifecycle (from the time it has been requested until the time
// it is no longer being considered as for redirect) we assign a reason for why its lifecycle
// has ended
enum SkillLifecycleEndState {
    // the skill's lifecycle has not ended
    NONE = 0,
    // the skill is no longer pending because another skill has taken its place as the pending skill
    PENDING_SKILL_SWITCH_INTERRUPTED = 1,
    // the skill switch request was denied because we can't switch out of the current or pending skill
    SKILL_SWITCH_REQUEST_DENIED = 2,
    // the skill's refresh method was not able to be called successfully
    SKILL_REFRESH_FAILED = 3,
    // the skill's open method was not able to be called successfully
    SKILL_OPEN_FAILED = 4,
    // the skill's close method and close recovery was not able to be called successfully
    SKILL_CLOSE_FAILED = 5,
    // a skill has been exited either by itself or by another skill redirect
    SKILL_EXITED = 6,
    // a skill has been exited either by itself or by another skill redirect
    SKILL_REFRESHED = 7
};

export default SkillLifecycleEndState;
