import SkillLifecycle from './SkillLifecycle';
import SkillSwitchData from './SkillSwitchData';
import SkillLifecycleState from './SkillLifecycleState';
import SkillLifecycleEndState from './SkillLifecycleEndState';

class SkillRedirectToken {

    private _skillLifecycle: SkillLifecycle;
    private _skillSwitchData: SkillSwitchData;

    constructor(skillLifecycle: SkillLifecycle, skillSwitchData: SkillSwitchData) {
        this._skillLifecycle = skillLifecycle;
        this._skillSwitchData = skillSwitchData;
    }

    get skillLifecycleState(): SkillLifecycleState {
        return this._skillLifecycle.skillLifecycleState;
    }

    get skillLifecycleEndState(): SkillLifecycleEndState {
        return this._skillLifecycle.skillLifecycleEndState;
    }

    get skillSwitchData(): SkillSwitchData {
        return this._skillSwitchData;
    }

    addOnSkillLifecycleStateChange(callback:(prevLifecycleState: SkillLifecycleState, currentLifecycleState: SkillLifecycleState) => void): void {
        this._skillLifecycle.addOnSkillLifecycleStateChange((prevLifecycleState: SkillLifecycleState, currentLifecycleState: SkillLifecycleState)=>{
            callback(prevLifecycleState, currentLifecycleState);
        });
    }

    addOnSkillLifecycleEnd(callback:(skillLifecycleEndState: SkillLifecycleEndState) => void): void {
        this._skillLifecycle.addOnSkillLifecycleEnd((skillLifecycleEndState: SkillLifecycleEndState)=>{
            callback(skillLifecycleEndState);
        });
    }

    onState(lifecycleState: SkillLifecycleState, callback:() => void): void {
        if(this._skillLifecycle.skillLifecycleState >= lifecycleState) {
            callback();
        } else {
            this._skillLifecycle.addOnSkillLifecycleStateChange((prevLifecycleState: SkillLifecycleState, currentLifecycleState: SkillLifecycleState) => {
                if(lifecycleState === currentLifecycleState) {
                    callback();
                }
            });
        }
    }
}

export default SkillRedirectToken;
