import SkillLifecycleState from './SkillLifecycleState';
import SkillLifecycleEndState from './SkillLifecycleEndState';
import parentLog from './log';
import SkillSwitchData from './SkillSwitchData';
import jibo = require('jibo');

class SkillLifecycle {

    private _skillSwitchData: SkillSwitchData;
    private _onSkillLifecycleStateChangeCallbackSet: Set<(prevLifecycleState:SkillLifecycleState, currentLifecycleState:SkillLifecycleState)=>void>;
    private _onSkillLifecycleEndCallbackSet: Set<(skillLifecycleEndState: SkillLifecycleEndState)=>void>;
    private _prevSkillLifecycleState: SkillLifecycleState;
    private _skillLifecycleEndState: SkillLifecycleEndState;
    public log: typeof jibo.log;
    private _skillLifecycleState: SkillLifecycleState;

    constructor(skillSwitchData: SkillSwitchData) {
        this._skillSwitchData = skillSwitchData;

        this._onSkillLifecycleStateChangeCallbackSet = new Set();
        this._onSkillLifecycleEndCallbackSet = new Set();

        this._prevSkillLifecycleState = null;
        this._setSkillLifecycleState(SkillLifecycleState.NONE);
        this._skillLifecycleEndState = SkillLifecycleEndState.NONE;

        this.log = parentLog.createChild("SkillLifecycle")
    }

    get skillSwitchData(): SkillSwitchData {
        return this._skillSwitchData;
    }

    get skillLifecycleState(): SkillLifecycleState {
        return this._skillLifecycleState;
    }

    get skillLifecycleEndState(): SkillLifecycleEndState {
        return this._skillLifecycleEndState;
    }

    addOnSkillLifecycleStateChange(callback: (prevLifecycleState: SkillLifecycleState, currentLifecycleState: SkillLifecycleState) => void): boolean {
        if(this._onSkillLifecycleStateChangeCallbackSet.has(callback)) {
            return false;
        }
        this._onSkillLifecycleStateChangeCallbackSet.add(callback);
        return true;
    }

    addOnSkillLifecycleEnd(callback:(skillLifecycleEndState: SkillLifecycleEndState) => void): boolean {
        let returnValue = false;
        if(!this._onSkillLifecycleEndCallbackSet.has(callback)) {
            this._onSkillLifecycleEndCallbackSet.add(callback);
            returnValue = true;
        }

        // if the lifecycle has already ended, immediately call the callback with the lifecycle end state
        if(this._skillLifecycleState === SkillLifecycleState.LIFECYCLE_ENDED) {
            this._callOnSkillLifecycleEndCallbacks();
        }

        return returnValue;
    }

    skillSwitchRequested(): boolean {
        if(this._skillLifecycleState === SkillLifecycleState.NONE) {
            this._setSkillLifecycleState(SkillLifecycleState.SKILL_SWITCH_REQUESTED);
            return true;
        }
        return false;
    }

    skillSwitchPending(): boolean {
        if(this._skillLifecycleState === SkillLifecycleState.SKILL_SWITCH_REQUESTED) {
            this._setSkillLifecycleState(SkillLifecycleState.SKILL_SWITCH_PENDING);
            return true;
        }
        return false;
    }

    startSkillOpen(): boolean {
        if(this._skillLifecycleState === SkillLifecycleState.SKILL_SWITCH_PENDING) {
            this._setSkillLifecycleState(SkillLifecycleState.SKILL_START_OPEN);
            return true;
        }
        return false;
    }

    skillOpened(): boolean {
        if(this._skillLifecycleState === SkillLifecycleState.SKILL_START_OPEN) {
            this._setSkillLifecycleState(SkillLifecycleState.SKILL_OPENED);
            return true;
        }
        return false;
    }

    skillLifecycleEnded(skillLifecycleEndState: SkillLifecycleEndState): boolean {
        if(this._skillLifecycleState === SkillLifecycleState.LIFECYCLE_ENDED) {
            return false;
        }

        this._skillLifecycleEndState = skillLifecycleEndState;
        this._setSkillLifecycleState(SkillLifecycleState.LIFECYCLE_ENDED);

        this._callOnSkillLifecycleEndCallbacks();

        return true;
    }

    _setSkillLifecycleState(skillLifecycleState: SkillLifecycleState): void {
        this._prevSkillLifecycleState = this._skillLifecycleState;
        this._skillLifecycleState = skillLifecycleState;

        if(this._prevSkillLifecycleState !== this._skillLifecycleState) {
            if(this._onSkillLifecycleStateChangeCallbackSet.size > 0) {
                this._onSkillLifecycleStateChangeCallbackSet.forEach((lifecycleStateChangeCallback)=>{
                    try {
                        lifecycleStateChangeCallback(this._prevSkillLifecycleState, this._skillLifecycleState);
                    } catch(err) {
                        this.log.error("SkillSwitch: caught exception in onSkillLifecycleStateChange callback", err, lifecycleStateChangeCallback);
                    }
                });
            }
        }
    }

    _callOnSkillLifecycleEndCallbacks(): void {
        if(this._onSkillLifecycleEndCallbackSet.size > 0) {
            this._onSkillLifecycleEndCallbackSet.forEach((lifecycleEndCallback)=>{
                try {
                    lifecycleEndCallback(this._skillLifecycleEndState);
                } catch(err){
                    this.log.error("SkillSwitch: caught exception in onSkillLifecycleEnd callback", err);
                }
            });
        }
    }
}

export default SkillLifecycle;
