import {BeSkill} from '@be/be-framework';

/**
 * Class supplied to the Jibo library so that it (particularly MIMs) can send data to
 * our analytics service.
 */
class LibraryAnalytics {
    get currentSkill(): string {
        const plugin = BeSkill.plugins.analytics;
        if (plugin) {
            return plugin.currentSkill;
        }
        return 'none';
    }

    set LOG_TO_CONSOLE(value) {
        const plugin = BeSkill.plugins.analytics;
        if (plugin && plugin._segmentAnalytics) {
            plugin._segmentAnalytics.LOG_TO_CONSOLE = value;
        }
    }

    track(event: string, data: Object): void {
        const plugin = BeSkill.plugins.analytics;
        if (plugin) {
            plugin.skillEvent(event, data);
        }
    }

    flush(): void {
        const plugin = BeSkill.plugins.analytics;
        if (plugin) {
            plugin.flush();
        }
    }
}

export default LibraryAnalytics;
