import jibo = require('jibo');
import path = require('path');
import {BeSkill, ExitOptions} from '@be/be-framework';
import TimerSpy from './TimerSpy';
import parentLog from './log';
import SkillSwitchData, {Options} from './SkillSwitchData';
import SkillLifecycle from './SkillLifecycle';
const log = parentLog.createChild("SkillSwitchUtil");

const packageInfo = require(path.join(
    jibo.utils.PathUtils.findRoot(),
    'package.json'
));

const closeSkillTimeoutMS = 5000;
const openSkillTimeoutMS = 5000;

class SkillSwitchUtil {

    public static log: typeof jibo.log;

    static canSkillSwitch(currentSkillSwitchData: SkillSwitchData, newSkillSwitchData: SkillSwitchData): boolean {
        // if the current skill priority is greater than the new skill priority , then we need to know
        // if the current skill is interruptible to figure out if skill switching is allowed
        // but if the new skill is proactively launched then dont interrupt the current skill even if it allows interruptions
        if (currentSkillSwitchData.priority > newSkillSwitchData.priority) {
            if (newSkillSwitchData.options && newSkillSwitchData.options.match && newSkillSwitchData.options.match.isProactive) {
                log.info(`proactive skill switch request denied because current skill ${currentSkillSwitchData.name} has higher priority`);
                return false;
            } else {
                return currentSkillSwitchData.skill.isInterruptible;
            }
        }
        // otherwise the new skill is of higher or equal priority, so we always allow for skill switching
        // regardless if the skill is interruptible or not
        else {
            return true;
        }
    }

    static closeSkill(skill: BeSkill, pendingSkillName?: string): Promise<void> {
        let closeTimeout:NodeJS.Timer = null;
        return new Promise((resolve, reject)=>{

            closeTimeout = setTimeout(()=>{
                return reject('skill took too long to close. Force closing.');
            }, closeSkillTimeoutMS);

            if(skill) {
                try {
                    log.info("stopping " + skill.assetPack);
                    // reset skipSurprisesExternal flag at close
                    skill.skipSurprisesExternal = false;
                    skill.close(resolve, pendingSkillName);
                } catch(err) {
                    log.error(err);
                    return reject(err);
                }
            } else {
                return resolve();
            }
        })
        .catch((err)=>{
            return err;
        })
        // the error parameter here would be passed from the skill's close method
        .then((err)=>{
            clearTimeout(closeTimeout);
            if(err) {
                log.error(`Skill closing failed: ${err}.  Cleaning up cache anyway.`);
                // clear the face renderer stage and eye animations
                jibo.face.reset();
                // cancel all pending loads
                jibo.loader.assetManager.cancelAll();
            }
            // Current skill is closed completely
            // flag an error if the current cache is not the skill's id.
            // this means something changed the default cache while the skill was running and assets may have been
            // cached in the wrong bucket
            if(skill) {
                if(jibo.loader.activeCache !== skill.assetPack) {
                    log.error(`While closing skill ${skill.assetPack}, expected active cache to be ${skill.assetPack} but is ${jibo.loader.activeCache}.  Something may have changed the default / active cache while the skill was closing.`);
                }

                // auto delete memory check - deleteCache unloads assets, it does not require the
                // cache to be re-added later
                if(!packageInfo.jibo.debug.noCacheDestroy) {
                    jibo.loader.deleteCache(skill.assetPack);
                }

                jibo.expression.destroyCaches(skill.assetPack);
            }
            //mark the active cache as null just to give more warnings if anyone tries
            //funny business like trying to load into the current skill cache between skills
            jibo.loader.activeCache = null;
            jibo.embodied.speech.setPaths(null);

            if(packageInfo.jibo.debug.resourceLeak && skill) {
                // check our timer spy to make sure all update loops have been cleaned up from the skill!
                TimerSpy.instance.checkSkillCleanup();
            }

            // send skill exit analytics event
            BeSkill.plugins.analytics.skillExit(pendingSkillName);
        });
    }

    /**
     * Open the named skill and set it to current.
     * NOTE this assumes the current skill has been closed
     * @name openSkill
     * @param newSkill {skill} - the new skill to be launched
     * @param asrResults {Object} - the asr options to launch a new skill
     * @param done {function} - callback to signal the new skill has been loaded
     * @type {BeSkill}
     */
    static openNewSkill(currentSkillLifecycle: SkillLifecycle, newSkillLifecycle: SkillLifecycle): Promise<SkillSwitchData> {

        const newSkillName = newSkillLifecycle.skillSwitchData.name;
        const newSkillOptions = newSkillLifecycle.skillSwitchData.options;
        let openTimeout: NodeJS.Timer = null;
        let oldSkillName: string = null;
        return new Promise((resolve, reject)=>{

            openTimeout = setTimeout(()=>{
                return reject('skill took too long to open. Force closing.');
            }, openSkillTimeoutMS);

            oldSkillName = currentSkillLifecycle? currentSkillLifecycle.skillSwitchData.skill.assetPack : '';

            jibo.loader.basePath = newSkillLifecycle.skillSwitchData.skill.rootPath;
            jibo.sound.basePath = newSkillLifecycle.skillSwitchData.skill.rootPath;
            // set the active / default cache to the skills id we're switching into
            //addCache does nothing if the cache already exists
            jibo.loader.addCache(newSkillLifecycle.skillSwitchData.skill.assetPack);
            jibo.loader.activeCache = newSkillLifecycle.skillSwitchData.skill.assetPack;
            // set the Embodied Speech paths to the skills assetPack we're switching into
            jibo.embodied.speech.setPaths(newSkillLifecycle.skillSwitchData.skill.assetPack);
            //do a somewhat hacky method of detecting voice skill launches so we can turn off silent menus
            //if the options exist and have a truthy Input property, then it is a pretty safe bet that the options are a
            //nlu object from an actual voice interaction.
            if (newSkillOptions && newSkillOptions.asr.text) {
                jibo.mim.silentMenus = false;
            }

            try {
                log.info("BeSkill open", oldSkillName, newSkillName, newSkillOptions);
                BeSkill.open(oldSkillName, newSkillLifecycle.skillSwitchData.skill.assetPack, newSkillOptions, (err) => {
                    try {
                        if (err) {
                            log.error(err);
                        }
                        log.info("new skill preload", newSkillName);
                        newSkillLifecycle.skillSwitchData.skill.preload((err) => {
                            return resolve(err);
                        });
                    } catch(err) {
                        return reject(err);
                    }
                });
            } catch(err) {
                return reject(err);
            }
        })
        .catch((err)=>{
            return err;
        })
        .then((err)=>{
            clearTimeout(openTimeout);
            return new Promise<SkillSwitchData>((resolve, reject)=>{
                if(err) {
                    return reject(err);
                }

                try {
                    log.info("opening new skill", newSkillName);
                    // send analytics event for skill entry
                    BeSkill.plugins.analytics.skillEntry(newSkillName, newSkillOptions, oldSkillName);
                    let currentSkillName = currentSkillLifecycle ? currentSkillLifecycle.skillSwitchData.name : null;
                    let currentSkillOptions = currentSkillLifecycle ? currentSkillLifecycle.skillSwitchData.options : null;
                    newSkillLifecycle.skillSwitchData.skill.skipSurprisesExternal = newSkillOptions && newSkillOptions.match && newSkillOptions.match.skipSurprises;
                    newSkillLifecycle.skillSwitchData.skill.open(newSkillOptions, false, currentSkillName, currentSkillOptions);
                    return resolve(newSkillLifecycle.skillSwitchData);
                }
                catch(err) {
                    return reject(err);
                }
            });
        });
    }
}

SkillSwitchUtil.log = log;

export default SkillSwitchUtil;