import path = require('path');
import jibo = require('jibo');

class ModuleVersions {
    /**
     * Log the top level versions of each dependency
     */
    static log(log: typeof jibo.log, beRootDir: string): void {
        // Generate exact dependency information as running:
        // `npm ls --depth=0 --production` at the root of Be would output
          // Load Be's package.json
        const bePackageJson = require(path.resolve(beRootDir, "package.json"));
        // Go through each of Be's production dependencies and look up it's
          // on disk version
        let packageInfo: {[packageName: string]: string} = {};
        for (let packageName in bePackageJson.dependencies) {
            try{
                const packageJson = require(path.resolve(beRootDir, "node_modules", packageName, "package.json"));
                packageInfo[packageName] = packageJson.version;
            } catch(error) {
                packageInfo[packageName] = "Not Installed? (Hoisted?)";
            }
        }

        if (  jibo.runMode !== undefined &&
              jibo.runMode !== jibo.RunMode.UNIT_TESTS) {
            // log version information to syslog
            log.info('Skill versions:', packageInfo);
        }
    }
}

export default ModuleVersions;
