import jibo = require( 'jibo');
import EventEmitter = require('jibo-eventemitter3');
import parentLog from './log';
const log = parentLog.createChild("TimerSpy");

type CompleteCallback = (call: jibo.utils.DelayedCall) => void;

class TimerSpy {

    /**
    * The structure of the timer spies are the following
    * Object { skillName1=>Map, skillName2=>Map }
    * There are 3 types of maps:
    * For events: "eventName" => Set, Set<callbacks>
    * for Timeouts: callback => delayedCall
    * for Intervals: callback => delayedCall
    **/

    private static _instance: TimerSpy;
    public log: typeof jibo.log;
    private _globalTimerSymbol: symbol;
    private _initRan: boolean;
    private _getCurrentSkillNameCallback: () => string;
    private _skillTimers: Object;
    private _originalOn: (event: string, fn: Function, context?: any) => EventEmitter;
    private _originalRemoveListener: (event: string, fn?: Function, context?: any, once?: boolean) => EventEmitter;
    private _originalSetTimeout: (callback: CompleteCallback, delay: number, useFrames?: boolean, autoDestroy?: boolean) => jibo.utils.DelayedCall;
    private _originalClearTimeout: (call: jibo.utils.DelayedCall) => void;
    private _originalSetInterval: (callback: CompleteCallback, delay: number, useFrames?: boolean) => jibo.utils.DelayedCall;
    private _originalClearInterval: (call: jibo.utils.DelayedCall) => void;

    public static get instance(): TimerSpy {
        if(!TimerSpy._instance) {
            TimerSpy._instance = new TimerSpy();
        }

        return TimerSpy._instance;
    }

    constructor() {
        //expose log to unit tests for mocking/spying
        this.log = log;
        this._globalTimerSymbol = Symbol("global");
        this._initRan = false;
    }

    set getCurrentSkillNameCallback(value: () => string) {
        this._getCurrentSkillNameCallback = value;
    }

    init(getCurrentSkillNameCallback:() => string): void {
        this._initRan = true;
        this._getCurrentSkillNameCallback = getCurrentSkillNameCallback;
        this._skillTimers = {};

        this._originalOn = jibo.timer.on.bind(jibo.timer);
        this._originalRemoveListener = jibo.timer.removeListener.bind(jibo.timer);
        this._originalSetTimeout = jibo.timer.setTimeout.bind(jibo.timer);
        this._originalClearTimeout = jibo.timer.clearTimeout.bind(jibo.timer);
        this._originalSetInterval = jibo.timer.setInterval.bind(jibo.timer);
        this._originalClearInterval = jibo.timer.clearInterval.bind(jibo.timer);

        jibo.timer.on = this.onOverride.bind(this);
        jibo.timer.off = jibo.timer.removeListener = this.removeListenerOverride.bind(this);

        jibo.timer.setTimeout = this.setTimeoutOverride.bind(this);
        jibo.timer.clearTimeout = this.clearTimeoutOverride.bind(this);

        jibo.timer.setInterval = this.setIntervalOverride.bind(this);
        jibo.timer.clearInterval = this.clearIntervalOverride.bind(this);
    }

    restore(): void {
        if(this._initRan) {
            jibo.timer.on = this._originalOn;
            jibo.timer.off = jibo.timer.removeListener = this._originalRemoveListener;

            jibo.timer.setTimeout = this._originalSetTimeout;
            jibo.timer.clearTimeout = this._originalClearTimeout;

            jibo.timer.setInterval = this._originalSetInterval;
            jibo.timer.clearInterval = this._originalClearInterval;
        }
    }

    getCurrentSkillTimers(skillName: string|symbol): Map<any,any> {
        if(!this._skillTimers[skillName]) {
            this._skillTimers[skillName] = new Map();
        }

        return this._skillTimers[skillName];
    }

    checkSkillCleanup(): void {
        let skillTimers = this.getCurrentSkillTimers(this._getCurrentSkillNameCallback());
        if(skillTimers.size !== 0) {
            log.error("The current skill has uncleaned up timers!!", this._getCurrentSkillNameCallback(), skillTimers);

            // // auto cleanup!!
            // for(let [key, mapVal] of skillTimers.entries()) {
            //     if(mapVal instanceof Set) {
            //         for(let valSetEntry of mapVal) {
            //             this._originalRemoveListener(key, valSetEntry);
            //         }
            //     } else {
            //         skillTimers.get(key).destroy();
            //     }
            // }

            // clear out all the rogue entries
            delete this._skillTimers[this._getCurrentSkillNameCallback()];
        } else {
            log.info("The current skill cleaned up all timers", this._getCurrentSkillNameCallback());
        }
    }

    onOverride(event: string, method: Function): EventEmitter {
        const skillName = (method as any).isGlobalTimer ? this._globalTimerSymbol : this._getCurrentSkillNameCallback();
        let skillTimers = this.getCurrentSkillTimers(skillName);

        let eventMethodSet = null;
        if(!skillTimers.has(event)) {
            eventMethodSet = new Set();
            skillTimers.set(event, eventMethodSet);
        } else {
            eventMethodSet = skillTimers.get(event);
        }

        // if something tried adding the same callback twice, we should log an error but DONT prevent the duplicate from being added
        if(eventMethodSet.has(method)) {
            log.error("Found timeout being set from skill: ", skillName, method);
            eventMethodSet.delete(method);
        }
        eventMethodSet.add(method);

        return this._originalOn(event, method);
    }

    removeListenerOverride(event: string, method: Function): EventEmitter{
        const skillName = (method as any).isGlobalTimer ? this._globalTimerSymbol : this._getCurrentSkillNameCallback();
        let skillTimers = this.getCurrentSkillTimers(skillName);

        let eventMethodSet: Set<Function> = skillTimers.get(event);
        if(eventMethodSet) {
            eventMethodSet.delete(method);
            if(eventMethodSet.size === 0) {
                skillTimers.delete(event);
            }
        }

        return this._originalRemoveListener(event, method);
    }

    setTimeoutOverride(callback: CompleteCallback, delay: number, useFrames: boolean, autoDestroy: boolean): jibo.utils.DelayedCall{
        const skillName = (callback as any).isGlobalTimer ? this._globalTimerSymbol : this._getCurrentSkillNameCallback();
        let skillTimers = this.getCurrentSkillTimers(skillName);

        // if something tried adding the same callback twice, we should log an error but DONT prevent the duplicate from being added
        if(skillTimers.has(callback)) {
            log.error("Found timeout being set from skill: ", skillName, callback);
            skillTimers.delete(callback);
        }

        let delayedCall: jibo.utils.DelayedCall = this._originalSetTimeout(callback, delay, useFrames, autoDestroy);
        (delayedCall as any).isGlobalTimer = (callback as any).isGlobalTimer;

        // since the implementation of jibo.timer's setTimeout is just an update tick entry,
        // jibo.timer will actually create a non-global entry under the skill.
        // so we need to look it up and remove the update. awful i know.
        let currentSkillTimers = this.getCurrentSkillTimers(this._getCurrentSkillNameCallback());
        if((callback as any).isGlobalTimer && currentSkillTimers &&
            currentSkillTimers.get("update") &&
            currentSkillTimers.get("update").has((delayedCall as any)._update)) {

            currentSkillTimers.get("update").delete((delayedCall as any)._update);
            if(currentSkillTimers.get("update").size === 0) {
                currentSkillTimers.delete("update");
            }
        }

        skillTimers.set(delayedCall, callback);

        const originalDestroy = delayedCall.destroy.bind(delayedCall);
        delayedCall.destroy = ()=>{
            originalDestroy();
            this.clearTimeoutOverride(delayedCall);
        };

        return delayedCall;
    }

    clearTimeoutOverride(delayedCall: jibo.utils.DelayedCall): void {
        const skillName = (delayedCall as any).isGlobalTimer ? this._globalTimerSymbol : this._getCurrentSkillNameCallback();
        let skillTimers = this.getCurrentSkillTimers(skillName);

        if(skillTimers.get(delayedCall)) {
            skillTimers.delete(delayedCall);
            return this._originalClearTimeout(delayedCall);
        }
        return;
    }

    setIntervalOverride(callback: CompleteCallback, delay: number, useFrames: boolean): jibo.utils.DelayedCall{
        const skillName = (callback as any).isGlobalTimer ? this._globalTimerSymbol : this._getCurrentSkillNameCallback();
        let skillTimers = this.getCurrentSkillTimers(skillName);

        // if something tried adding the same callback twice, we should log an error but DONT prevent the duplicate from being added
        if(skillTimers.has(callback)) {
            log.error("Found interval being set from skill: ", skillName, callback);
            skillTimers.delete(callback);
        }

        let delayedCall: jibo.utils.DelayedCall = this._originalSetInterval(callback, delay, useFrames);
        (delayedCall as any).isGlobalTimer = (callback as any).isGlobalTimer;

        // since the implementation of jibo.timer's setTimeout is just an update tick entry,
        // jibo.timer will actually create a non-global entry under the skill.
        // so we need to look it up and remove the update. awful i know.
        let currentSkillTimers = this.getCurrentSkillTimers(this._getCurrentSkillNameCallback());
        if((callback as any).isGlobalTimer && currentSkillTimers &&
            currentSkillTimers.get("update") &&
            currentSkillTimers.get("update").has((delayedCall as any)._update)) {

            currentSkillTimers.get("update").delete((delayedCall as any)._update);
            if(currentSkillTimers.get("update").size === 0) {
                currentSkillTimers.delete("update");
            }
        }

        skillTimers.set(delayedCall, callback);

        const originalDestroy: () => void = delayedCall.destroy.bind(delayedCall);
        delayedCall.destroy = () => {
            originalDestroy();
            this.clearIntervalOverride(delayedCall);
        };

        return delayedCall;
    }

    clearIntervalOverride(delayedCall: jibo.utils.DelayedCall): void {
        const skillName = (delayedCall as any).isGlobalTimer ? this._globalTimerSymbol : this._getCurrentSkillNameCallback();
        let skillTimers = this.getCurrentSkillTimers(skillName);

        if(skillTimers.get(delayedCall)) {
            skillTimers.delete(delayedCall);
            return this._originalClearInterval(delayedCall);
        }
        return;
    }

    destroy(): void {
        this._initRan = false;
        this._skillTimers = {};
    }
}

export default TimerSpy;
